import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../repositories/providers.dart';
final courtStatusProvider = StateProvider((_)=>'all');
final adminCourtsProvider = StreamProvider((ref)=>ref.watch(adminRepositoryProvider).courts(ref.watch(courtStatusProvider)));
class CourtsScreen extends ConsumerWidget { const CourtsScreen({super.key}); @override Widget build(BuildContext context, WidgetRef ref)=>Scaffold(appBar: AppBar(title: const Text('Kelola Lapangan & Postingan')), body: Column(children:[Padding(padding: const EdgeInsets.all(16), child: SegmentedButton<String>(segments: const [ButtonSegment(value:'all',label:Text('Semua')),ButtonSegment(value:'pending',label:Text('Pending')),ButtonSegment(value:'approved',label:Text('Approved')),ButtonSegment(value:'rejected',label:Text('Rejected'))], selected:{ref.watch(courtStatusProvider)}, onSelectionChanged:(v)=>ref.read(courtStatusProvider.notifier).state=v.first)), Expanded(child: ref.watch(adminCourtsProvider).when(data:(items)=>ListView(padding: const EdgeInsets.all(16), children: items.map((c)=>Card(child: ListTile(leading: const Icon(Icons.sports_tennis), title: Text(c.name), subtitle: Text('${c.address}\n${c.status} • ${c.createdBy}'), isThreeLine: true, trailing: Wrap(children:[TextButton(onPressed:()=>ref.read(adminRepositoryProvider).setCourtStatus(c.courtId,'approved'), child: const Text('Approve')), TextButton(onPressed:()=>ref.read(adminRepositoryProvider).setCourtStatus(c.courtId,'rejected'), child: const Text('Reject')), IconButton(onPressed:(){}, icon: const Icon(Icons.edit_outlined))]))).toList()), error:(e,_)=>Center(child:Text('$e')), loading:()=>const Center(child:CircularProgressIndicator()))) ])); }
